$.fn.hyphenate=function(){var e="[邪斜胁谐写械褢卸蟹懈泄泻谢屑薪芯锌褉褋褌褍褎褏褑褔褕褖褗褘褜褝褞褟]";var t="[邪械褢懈芯褍褘褝褞褟]";var n="[斜胁谐写卸蟹泻谢屑薪锌褉褋褌褎褏褑褔褕褖]";var r="[泄褗褜]";var i="颅";var s=new RegExp("("+r+")("+e+e+")","ig");var o=new RegExp("("+t+")("+t+e+")","ig");var u=new RegExp("("+t+n+")("+n+t+")","ig");var a=new RegExp("("+n+t+")("+n+t+")","ig");var f=new RegExp("("+t+n+")("+n+n+t+")","ig");var l=new RegExp("("+t+n+n+")("+n+n+t+")","ig");this.each(function(){var e=$(this).html();e=e.replace(s,"$1"+i+"$2");e=e.replace(o,"$1"+i+"$2");e=e.replace(u,"$1"+i+"$2");e=e.replace(a,"$1"+i+"$2");e=e.replace(f,"$1"+i+"$2");e=e.replace(l,"$1"+i+"$2");$(this).html(e)})}
